    return await rust_bridge.analyzeWithUserChunks(userRanges: userRanges, totalPages: totalPages, sizeBytes: sizeBytes, config: config ?? HeuristicsConfig(enablePdfTextHeuristics: true, textLayerThreshold: 0.7, fileSizeThresholdBytes: 10485760, pageCountThreshold: 50, targetPagesPerChunk: 10, maxPagesPerChunk: 25, diskProcessingThresholdBytes: 52428800, minCharsPerPage: 50, maxXlsxSheetCount: 200, maxXlsxWorkbookCells: 5000000, maxPptxEmbeddedCount: 50));
  }

