  /// # Arguments
  ///
  /// * `path` - Path to the image file.
  /// * `llm_config` - LLM configuration for the VLM call.
  /// * `custom_prompt` - Optional custom caption prompt. Uses the default
  ///   `RegionKind::Caption` prompt when `None`.
  ///
  /// # Returns
  ///
  /// The generated caption text.
  ///
  /// # Errors
  ///
  /// Returns an error if the file cannot be read, if image format detection fails,
  /// or if the VLM call fails.
  ///
  /// # Example
  ///
  /// ```ignore
  /// use kreuzberg::captioning::caption_image_file;
  /// use kreuzberg::LlmConfig;
  ///
  /// # async fn example() -> kreuzberg::Result<()> {
  /// let config = LlmConfig {
  ///     model: "openai/gpt-4o-mini".to_string(),
  ///     ..Default::default()
  /// };
  /// let caption = caption_image_file("document_page_001.png", &config, None).await?;
  /// # Ok(())
  /// # }
  /// ```
  /// throws anyhow::Error on failure
  static Future<String> captionImageFile(String path, LlmConfig llmConfig, {String? customPrompt}) async {
    return await rust_bridge.captionImageFile(path: path, llmConfig: llmConfig, customPrompt: customPrompt);
  }

  /// Detect the MIME type of a file at the given path.
  ///
  /// Uses the file extension and optionally the file content to determine the MIME type.
  /// Set `check_exists` to `true` to verify the file exists before detection.
  /// throws anyhow::Error on failure
  static Future<String> detectMimeType(String path, bool checkExists) async {
    return await rust_bridge.detectMimeType(path: path, checkExists: checkExists);
  }

